class Solution:
    def pivotArray(self, nums, pivot):
        n = len(nums)
        result = [0] * n
        idx = 0
        for x in nums:
            if x < pivot:
                result[idx] = x
                idx += 1
        for x in nums:
            if x == pivot:
                result[idx] = x
                idx += 1
        for x in nums:
            if x > pivot:
                result[idx] = x
                idx += 1
        return result

