var pivotArray = function(nums, pivot) {
    const less = [];
    const equal = [];
    const greater = [];
    for (const x of nums) {
        if (x < pivot) less.push(x);
        else if (x === pivot) equal.push(x);
        else greater.push(x);
    }
    return less.concat(equal, greater);
};
